export const meta = {
  name: 'quad341-issue-dossiers',
  description: 'Classify quad341 open issues on gastownhall/beads against current main',
  phases: [{ title: 'Issues', detail: 'one reader per issue' }],
}

const ISSUES = [4982, 4960, 4314, 4018, 4016]

const SCHEMA = {
  type: 'object',
  required: ['number', 'category', 'evidence', 'nextAction'],
  properties: {
    number: { type: 'integer' },
    title: { type: 'string' },
    category: { type: 'string', enum: ['already-implemented', 'obsolete-premise', 'still-valid-feature-request', 'still-valid-bug', 'needs-maintainer-decision'] },
    evidence: { type: 'string', description: 'file:line / commit / PR citations backing the category' },
    draftComment: { type: 'string', description: 'if already-implemented or obsolete-premise: a short factual close-comment draft citing the evidence; else empty' },
    nextAction: { type: 'string' },
  },
}

phase('Issues')
const dossiers = await pipeline(
  ISSUES,
  n => agent(`Build a dossier for gastownhall/beads ISSUE #${n} by quad341. Read-only: gh + read-only git/grep on /var/home/matt/dev/mybd/bd-main (upstream/main is fetched; fetch again if stale: git -C /var/home/matt/dev/mybd/bd-main fetch upstream main). Do NOT edit, push, comment, or use bd.

1. gh issue view ${n} --repo gastownhall/beads --json title,body,comments,labels,createdAt — read fully.
2. Determine whether current upstream/main already implements or obsoletes the request: grep for the commands/flags/fields the issue asks about; check merged PRs (gh pr list --repo gastownhall/beads --state merged --search "<keywords>") and recent commits touching the area. Cite evidence precisely.
3. Note: the Postgres/MySQL backends were removed (#4857); the beads charter routes orchestration policy outside beads core and prefers metadata over schema for workflow-specific data — relevant when judging feature requests like mol_type or landing-verification.
4. Categorize: already-implemented (close-candidate; draft a short factual close comment citing commit/PR), obsolete-premise (close-candidate; same), still-valid-feature-request, still-valid-bug, needs-maintainer-decision (only when a human product call is genuinely required).
Your final output is the structured object only.`,
    { label: `issue:${n}`, phase: 'Issues', model: 'sonnet', schema: SCHEMA })
)
const ok = dossiers.filter(Boolean)
log(`issue dossiers: ${ok.length}/${ISSUES.length}; spent ~${Math.round(budget.spent()/1000)}k`)
return { dossiers: ok }
